{
  "analysis": "We have downloaded the correct source tarballs: `rstan_2.32.7.tar.gz` from current CRAN and `StanHeaders_2.32.7.tar.gz` from CRAN Archive. The dataset has 68 rows. We need create the Stan model and R script, install binary dependencies via apt, then install the exact source versions of StanHeaders and rstan.",
  "plan": "I will create `hierarchical_model.stan` implementing the hierarchical binomial-beta model with the improper prior `(alpha+beta)^(-5/2)`, create `analysis.R` using `rstan::sampling` with 4 chains, 100,000 iterations, and seed 1, set up C++ Makevars for compilation, and start installing `r-cran-rstan` via apt to get all binary dependencies quickly.",
  "commands": [
    {
      "keystrokes": "cat > /app/hierarchical_model.stan <<'EOF'
data {
  int<lower=1> N;
  array[N] int<lower=0> y;
  array[N] int<lower=1> n;
}
parameters {
  real<lower=0> alpha;
  real<lower=0> beta;
  vector<lower=0, upper=1>[N] theta;
}
model {
  // Prior on (alpha, beta): proportional to (alpha + beta)^(-5/2)
  target += -2.5 * log(alpha + beta);

  // Group-level prior
  theta ~ beta(alpha, beta);

  // Likelihood
  y ~ binomial(n, theta);
}
EOF
",
      "duration": 0.1
    },
    {
      "keystrokes": "cat > /app/analysis.R <<'EOF'
library(rstan)

# Set rstan options
rstan_options(auto_write = TRUE)
options(mc.cores = 4)

# Load dataset
data <- read.csv("/app/data.csv")
stan_data <- list(
  N = nrow(data),
  y = as.integer(data$y),
  n = as.integer(data$n)
)

# Compile Stan model
model <- stan_model(file = "/app/hierarchical_model.stan")

# Posterior sampling using rstan::sampling
fit <- rstan::sampling(
  object = model,
  data = stan_data,
  chains = 4,
  iter = 100000,
  seed = 1
)

# Extract posterior samples and compute posterior means
samples <- rstan::extract(fit)
alpha_mean <- mean(samples$alpha)
beta_mean <- mean(samples$beta)

# Save results
writeLines(as.character(alpha_mean), "/app/posterior_alpha_mean.txt")
writeLines(as.character(beta_mean), "/app/posterior_beta_mean.txt")

cat("Posterior mean of alpha:", alpha_mean, "\n")
cat("Posterior mean of beta:", beta_mean, "\n")
EOF
",
      "duration": 0.1
    },
    {
      "keystrokes": "mkdir -p ~/.R
cat > ~/.R/Makevars <<'EOF'
CXX14 = g++
CXX14FLAGS = -O3 -mtune=native -march=native -Wno-unused-variable -Wno-unused-function -Wno-maybe-uninitialized
CXX14STD = -std=c++14
EOF
",
      "duration": 0.1
    },
    {
      "keystrokes": "apt-get update && apt-get install -y --no-install-recommends r-cran-rstan
",
      "duration": 60.0
    }
  ]
}
